import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

/**
 * Test for the issue where an empty THEN block causes a NullPointerException.
 * See: https://github.com/pinterest/ktlint/issues/xyz
 *
 * The problem occurs with code like:
 * ```
 * if ("a" == "b") {
 * } else if ("b" == "c") else {
 * }
 * ```
 * Where `else if ("b" == "c") else` has an empty THEN block after the condition.
 */
class MultiLineIfElseRuleEmptyThenTest {
    private val multiLineIfElseRuleAssertThat = assertThatRule { MultiLineIfElseRule() }

    @Test
    fun `Given an if-else statement with empty THEN block should not crash`() {
        val code =
            """
            fun foo() {
                if ("a" == "b") {
                } else if ("b" == "c") else {
                }
            }
            """.trimIndent()
        // The main goal is to not crash - no lint violations expected for empty THEN block
        multiLineIfElseRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a simple if-else statement with empty THEN block should not crash`() {
        val code =
            """
            fun foo() {
                if ("a" == "b") else {
                    println("else")
                }
            }
            """.trimIndent()
        // The main goal is to not crash - empty THEN block should be ignored
        multiLineIfElseRuleAssertThat(code).hasNoLintViolations()
    }
}
"}

