    private val multiLineIfElseRuleAssertThat = assertThatRule { MultiLineIfElseRule() }

    @Test
    fun `Given an if-else statement with empty THEN block should not crash`() {
        val code =
            """
            fun foo() {
                if ("a" == "b") {
                } else if ("b" == "c") else {
                }
            }
            """.trimIndent()
        // The main goal is to not crash - no lint violations expected for empty THEN block
        multiLineIfElseRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a simple if-else statement with empty THEN block should not crash`() {
        val code =
